import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        while (fs.hasNext()) {
            long a = fs.nextLong();
            if (!fs.hasNext()) break; // incomplete pair, ignore
            long b = fs.nextLong();
            long sum = a + b;
            long result = sum * 10 + 1;
            sb.append(result).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        boolean hasNext() throws IOException {
            int c;
            while ((c = readByte()) != -1) {
                if (!Character.isWhitespace(c)) { ptr--; return true; }
            }
            return false;
        }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) != -1 && Character.isWhitespace(c));
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c != -1 && !Character.isWhitespace(c)) {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = list(map(int, sys.stdin.read().split()))
    out_lines = []
    for i in range(0, len(data), 2):
        if i + 1 >= len(data):
            break
        a, b = data[i], data[i+1]
        s = a + b
        out_lines.append(str(s * 10 + 1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

